parameters.jsCode:
const b = $input.first().json.body ?? $input.first().json;
const out = [];
for (const c of b.commits ?? []) {
  const msg = c.message.split('\n')[0];
  let category = 'commit';
  if (/^feat/i.test(msg)) category = 'feature';
  else if (/^fix/i.test(msg)) category = 'bugfix';
  else if (/deploy/i.test(msg)) category = 'deployment';
  out.push({ json: {
    user_github: b.repository?.owner?.login ?? b.sender?.login,
    source: 'github',
    category,
    title: msg,
    metadata: JSON.stringify({ sha: c.id, url: c.url, repo: b.repository?.full_name }),
    event_date: (c.timestamp ?? new Date().toISOString()).slice(0, 10),
    event_time: c.timestamp ?? new Date().toISOString(),
  }});
}
return out;

