INSERT INTO ship_events (user_id, source, category, title, metadata, event_date, event_time)
SELECT p.id, $1::event_source, $2::event_category, $3, $4::jsonb, $5::date, $6::timestamptz
FROM profiles p WHERE p.github_username = $7;
